#!/usr/bin/env node
// apply-telegram-menu-disable.js
// Merges the patch at /Users/ainchorsoc2a/.openclaw/tmp/telegram-menu-disable.patch.json5
// into /Users/ainchorsoc2a/.openclaw/openclaw.json.
//
// The patch is a JSON5 subset (regular JSON works as JSON5) that targets
// channels.telegram.accounts.<id>.commands.{native,nativeSkills} for each
// of the three configured accounts: yoda, aria, Foodie.
//
// Behaviour:
//   - Validates current openclaw.json parses
//   - For each known account, sets commands.native = false and
//     commands.nativeSkills = false (overwrite if present)
//   - Writes back preserving 2-space indentation
//   - Refuses to touch botToken, allowFrom, groupAllowFrom, secrets.providers,
//     bindings, or any other field
//   - Refuses to run if patch is missing
//
// Ken approval is required before running. This script is provided for review;
// the main agent (Yoda) will invoke it only after explicit approval.
import fs from 'node:fs';
import path from 'node:path';

const CFG = '/Users/ainchorsoc2a/.openclaw/openclaw.json';
const PATCH = '/Users/ainchorsoc2a/.openclaw/tmp/telegram-menu-disable.patch.json5';
const ACCOUNTS = ['yoda', 'aria', 'Foodie'];

function readJson(p) {
  return JSON.parse(fs.readFileSync(p, 'utf8'));
}

const cfg = readJson(CFG);
const patch = readJson(PATCH);
const patchAccts = patch?.channels?.telegram?.accounts ?? {};
let changed = 0;
for (const id of ACCOUNTS) {
  const acct = cfg.channels?.telegram?.accounts?.[id];
  if (!acct) {
    console.error(`[skip] account ${id} not present in live config`);
    continue;
  }
  const want = patchAccts[id]?.commands;
  if (!want) {
    console.error(`[skip] patch has no commands block for ${id}`);
    continue;
  }
  acct.commands = { ...(acct.commands ?? {}), ...want };
  changed += 1;
  console.log(`[ok] ${id}.commands = ${JSON.stringify(acct.commands)}`);
}

// Validate
const text = JSON.stringify(cfg, null, 2);
JSON.parse(text); // round-trip
fs.writeFileSync(CFG, text + '\n');
console.log(`[done] ${changed} account(s) updated; wrote ${CFG} (${text.length} bytes)`);

